                            let cleaned = String(str)
                                .normalize('NFC')
                                .replace(/&eacute;/g, 'é')
                                .replace(/&egrave;/g, 'è')
                                .replace(/&ecirc;/g, 'ê')
                                .replace(/&agrave;/g, 'à')
                                .replace(/&acirc;/g, 'â')
